# Three decay functions for different memory durability requirements

import math, time

def exponential_decay(
    created_at: float,
    half_life_days: float = 14.0,
) -> float:
    """Standard decay: halves every half_life_days. Never reaches 0."""
    age_days = (time.time() - created_at) / 86400.0
    return math.exp(-math.log(2.0) * age_days / half_life_days)

def step_decay(
    created_at: float,
    ttl_days: float = 30.0,
) -> float:
    """Hard TTL: score = 1.0 until ttl_days, then immediately 0.0."""
    age_days = (time.time() - created_at) / 86400.0
    return 1.0 if age_days < ttl_days else 0.0

def linear_decay(
    created_at: float,
    max_age_days: float = 60.0,
) -> float:
    """Score decreases linearly from 1.0 to 0.0 over max_age_days."""
    age_days = (time.time() - created_at) / 86400.0
    return max(0.0, 1.0 - age_days / max_age_days)

# Importance-gated: high-importance memories decay slower
def importance_gated_decay(
    created_at: float,
    importance: float,          # 0–1
    base_half_life: float = 7.0,
) -> float:
    """
    importance=1.0 → half_life=4×base (very durable)
    importance=0.0 → half_life=0.25×base (evicted quickly)
    """
    scale = 0.25 + 3.75 * importance   # maps [0,1] → [0.25,4]
    half_life = base_half_life * scale
    return exponential_decay(created_at, half_life)

# DecayScorer: apply decay models to live Qdrant payload data
# Useful when you want to compute a decay-adjusted retrieval score
# at query time without updating every record in the database.

from qdrant_client import QdrantClient
from dataclasses import dataclass
from typing import Callable

client_q = QdrantClient(url="http://localhost:6333")

@dataclass
class DecayScorer:
    decay_fn: Callable[[float, ...], float] = exponential_decay
    half_life_days: float = 14.0

    def score(self, payload: dict) -> float:
        created_at = payload.get("created_at", time.time())
        importance = payload.get("importance", 0.5)
        if self.decay_fn is importance_gated_decay:
            return self.decay_fn(created_at, importance, self.half_life_days)
        return self.decay_fn(created_at, self.half_life_days)

    def rerank_by_decay(
        self,
        hits: list[dict],       # each has 'score' (similarity) and 'payload'
        alpha: float = 0.70,    # similarity weight
    ) -> list[dict]:
        """Blend cosine similarity with decay score, sort descending."""
        for h in hits:
            decay = self.score(h["payload"])
            h["decay_score"] = decay
            h["final_score"] = alpha * h["score"] + (1.0 - alpha) * decay
        hits.sort(key=lambda x: x["final_score"], reverse=True)
        return hits
